import React from 'react';
import { GoogleLogin } from '@react-oauth/google';
import { jwtDecode } from 'jwt-decode';

const Login = ({ onLogin }) => {
  const handleSuccess = (credentialResponse) => {
    const decoded = jwtDecode(credentialResponse.credential);
    onLogin(decoded);
    localStorage.setItem('admin_user', JSON.stringify(decoded));
  };

  const handleError = () => {
    console.error('Login Failed');
  };

  return (
    <div style={{
      display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100vh', backgroundColor: '#f4f4f4'
    }}>
      <div style={{
        padding: '40px', backgroundColor: 'white', borderRadius: '10px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)', textAlign: 'center'
      }}>
        <h1 style={{ marginBottom: '10px' }}>NeuraX Admin Core</h1>
        <p style={{ marginBottom: '30px', color: '#666' }}>Authenticate securely to access live municipal tracking</p>
        <GoogleLogin
          onSuccess={handleSuccess}
          onError={handleError}
          shape="pill"
        />
      </div>
    </div>
  );
};

export default Login;
